class Solution {
public:
    int numPairsDivisibleBy60(vector<int>& time) {
        int count[60] = {0};
        for (int t : time) {
            count[t % 60]++;
        }
        int res = 0;
        for (int i = 0; i < 30; i++) {
            res += count[i] * (count[60 - i] - (i == 0 ? 1 : 0));
        }
        res += count[30] * (count[30] - 1);
        return res;
    }
};
```
